function.body:
Cur_Parameter RECORD;
    v_atindpoPostventaId VARCHAR(32);	
    v_User_ID VARCHAR(32);
    v_Org_ID VARCHAR(32);
    v_Client_ID VARCHAR(32);
    v_tercero_cab varchar(60);
    v_lista_pre varchar(60);
    v_reg_val NUMBER:=0;
    v_lista_ver varchar(32);
    Cur_Productos RECORD;
    v_producto_id varchar(32);
    v_cantidad NUMBER:=0;
    v_tipo_producto varchar(32);
    v_tarifa NUMBER:=0;
    v_linea NUMBER:=0;
    v_lin_sin_imp NUMBER:=0;
    v_imp_lin NUMBER:=0;
    v_lin_con_imp NUMBER:=0;
    id varchar(32);
    acumula NUMBER:=0;
    total NUMBER:=0;
    v_tipo_prod varchar(60);
    v_product_cat varchar(32);
    v_cat_id varchar(32);


    v_linea_consol VARCHAR(32);
    v_orden_id varchar(32);
    v_org_orden VARCHAR(60);
    v_num_orden VARCHAR(30);
    v_tercero_orden VARCHAR(32);
    v_crear_factura VARCHAR(1);
    v_despacho VARCHAR(1);
    cuenta NUMBER:=0;


    v_ResultStr VARCHAR(2000):='';
    v_Message VARCHAR(2000):='';
	v_MessageReactivar VARCHAR(2000):='';
	v_MessageAnular VARCHAR(2000):='';
    v_Record_ID VARCHAR(32);
    v_Result NUMBER:=1;


BEGIN
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || p_PInstance_ID);
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'Y', NULL, NULL);

    BEGIN
        FOR Cur_Parameter IN
          (SELECT i.Record_ID,
                  i.AD_User_ID,
                  p.ParameterName,
                  p.P_String,
                  p.P_Number,
                  p.P_Date,
                  i.AD_Org_ID,
                  i.AD_Client_ID
             FROM AD_PInstance i
             LEFT JOIN AD_PInstance_Para p
               ON i.AD_PInstance_ID=p.AD_PInstance_ID
            WHERE i.AD_PInstance_ID=p_PInstance_ID
            ORDER BY p.SeqNo)
        LOOP
            v_atindpoPostventaId:=Cur_Parameter.Record_ID;
            v_User_ID:=Cur_Parameter.AD_User_ID;
            v_Org_ID:=Cur_Parameter.AD_Org_ID;
            v_Client_ID:=Cur_Parameter.AD_Client_ID;
        END LOOP;

        SELECT c_bpartner_id,m_pricelist_id
        INTO v_tercero_cab,v_lista_pre
        FROM atindpo_postventa
        WHERE atindpo_postventa_id=v_atindpoPostventaId;

        select count(indsup_consol_id)
        into v_reg_val
        from indsup_consol
        where atindpo_postventa_id=v_atindpoPostventaId
        and validado='N';

        IF (v_reg_val>0) then

              raise exception '%','Existen ordenes pendientes de validacion';

        end if;

        update atindpo_postventa set docstatus='EP' where atindpo_postventa_id=v_atindpoPostventaId;

        select m_pricelist_version_id
        into v_lista_ver
        from m_pricelist_version 
        where m_pricelist_id=v_lista_pre 
        order by validfrom desc limit 1;


        FOR Cur_Productos IN
	    (
        select l.m_product_id,p.producttype,sum(l.cantidad) as cantidad
        from indsup_consol c,atindpo_postventa a,atindpo_postventalinea l,m_product p
        where c.atindpo_postventa_id=v_atindpoPostventaId
        and c.organizacion=a.ad_org_id
        and c.orden=a.documentno
        and a.atindpo_postventa_id=l.atindpo_postventa_id
        and l.m_product_id=p.m_product_id
        group by l.m_product_id,p.producttype
        )
        LOOP
            v_producto_id:=Cur_Productos.m_product_id;
            v_cantidad:=Cur_Productos.cantidad;
            v_tipo_producto:=Cur_Productos.producttype;
            cuenta:=cuenta+1;

        select pricelist
        into v_tarifa
        from  m_productprice
        where m_product_id=v_producto_id
        and m_pricelist_version_id=v_lista_ver;


        select producttype,m_product_category_id
        into v_tipo_prod,v_product_cat
        from m_product
        where m_product_id=v_producto_id;


        select m_product_category_id
        into v_cat_id
        from m_product_category
        where m_product_category_id =(select parent_id 
                                      from ad_treenode
                                      where node_id =v_product_cat);


        v_linea:=v_linea+10;
        v_lin_sin_imp:=round((v_cantidad*v_tarifa),2);
        v_imp_lin:=round((v_lin_sin_imp*0.12),4);
        v_lin_con_imp:=round((v_lin_sin_imp+v_imp_lin),2);
        select get_uuid() into id;

        acumula:=acumula+v_lin_sin_imp;

        insert into atindpo_postventalinea (atindpo_postventalinea_id,atindpo_postventa_id,ad_client_id,ad_org_id,isactive,created,createdby,updated,updatedby,m_product_id,cantidad,entregado,line,atindpo_unitprice,atindpo_pricelist,atindpo_linenetamt,c_tax_id,atindpo_iva,atindpo_total,em_indsup_tipo,em_indsup_cat_id)
        VALUES (id,v_atindpoPostventaId,v_Client_ID,v_Org_ID,'Y',now(),v_User_ID,now(),v_User_ID,v_producto_id,v_cantidad,'N',v_linea,v_tarifa,v_tarifa,v_lin_sin_imp,'ECDA1AF9CB5840049E8AD048D4F85502',v_imp_lin,v_lin_con_imp,v_tipo_prod,v_cat_id);


        END LOOP;

        total:=to_char(round((acumula*1.12),2));

        update atindpo_postventa set grandtotal=total where atindpo_postventa_id=v_atindpoPostventaId;
        update atindpo_postventa set em_indsup_est_consol='GE',docstatus='TL' where atindpo_postventa_id=v_atindpoPostventaId;


        v_Message:=total;
        DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished - ' || v_Message) ;
        AD_UPDATE_PINSTANCE(p_PInstance_ID, v_User_ID, 'Y', v_Result, v_Message);
        RETURN;

    END;    
    EXCEPTION WHEN OTHERS THEN
        v_ResultStr:= '@ERROR=' || SQLERRM;
        DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
                AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr);
        RETURN;
END INDSUP_CONSOLIDA_ORD
